+    let after_set: BTreeSet<String> = after.iter().map(|c| c.as_str().to_string()).collect();
+
+    let added = after_set
+        .difference(&before_set)
+        .cloned()
+        .collect::<Vec<_>>();
+    let removed = before_set
+        .difference(&after_set)
+        .cloned()
